1	//! Unit G — Message Derivation Checks (clean-room reimplementation).
2	//!
3	//! For each protocol rule, the prover decides whether every variable of the rule
4	//! is derivable by the intruder from the rule's premises. Variables that are not
5	//! derivable are reported under the wellformedness topic `Message Derivation
6	//! Checks`. The derivability decision is the prover's solver and is NOT
7	//! reimplemented here: it is supplied by the caller through [`DerivabilitySolver`].
8	//!
9	//! This crate owns three things, all characterized purely by black-box
10	//! observation of the reference tool (see workspace/BEHAVIOR.md and QUERIES.log):
11	//!   1. probe construction — which rules and which variables are handed to the
12	//!      solver (rule filtering, candidate-variable enumeration);
13	//!   2. the decision logic around solver outcomes (deactivation, timeouts,
14	//!      derivable/not-derivable);
15	//!   3. byte-exact report text and variable ordering.
16	
17	pub mod ast;
18	
19	use std::collections::{BTreeSet, HashSet};
20	
21	use ast::{Rule, RuleAttr, SortHint, Term, TheoryItem, Theory, VarSpec, Fact};
22	
23	/// A single wellformedness finding: a topic and its message body. Mirrors the
24	/// `WfError` surface of the wellformedness unit so findings compose into the
25	/// shared report model.
26	#[derive(Debug, Clone, PartialEq, Eq)]
27	pub struct WfError {
28	    pub topic: String,
29	    pub message: String,
30	}
31	
32	impl WfError {
33	    pub fn new(topic: impl Into<String>, message: impl Into<String>) -> Self {
34	        WfError { topic: topic.into(), message: message.into() }
35	    }
36	}
37	
38	/// A flat report, in the order findings are rendered.
39	pub type WfReport = Vec<WfError>;
40	
41	/// The exact topic string the reference tool prints for this check.
42	pub const DERIVATION_TOPIC: &str = "Message Derivation Checks";
43	
44	/// The exact introductory paragraph the reference tool prints once, before the
45	/// per-rule blocks. Two leading spaces; no trailing whitespace.
46	pub const DERIVATION_INTRO: &str =
47	    "  The variables of the following rule(s) are not derivable from their premises, you may be performing unintended pattern matching.";
48	
49	// --------------------------------------------------------------------------
50	// Caller-supplied decision callback
51	// --------------------------------------------------------------------------
52	
53	/// One derivability question: can the intruder derive `variable` (X) from
54	/// `premises` (Y) of `rule`, within `timeout_secs`? The full `rule` is provided
55	/// so a solver that needs more context than the premise facts can use it.
56	pub struct DerivProbe<'a> {
57	    pub rule_name: &'a str,
58	    pub rule: &'a Rule,
59	    pub variable: &'a VarSpec,
60	    pub premises: &'a [Fact],
61	    pub timeout_secs: u64,
62	}
63	
64	/// The solver's verdict for one probe.
65	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
66	pub enum Derivability {
67	    /// The intruder can derive the variable from the premises.
68	    Derivable,
69	    /// The intruder cannot derive the variable — it will be reported.
70	    NotDerivable,
71	    /// The derivation search exceeded the timeout budget without deciding.
72	    TimedOut,
73	}
74	
75	/// The decision callback this crate is parameterized over. In production it wraps
76	/// the prover's message-deduction solver; in tests it is stubbed.
77	pub trait DerivabilitySolver {
78	    fn check(&self, probe: &DerivProbe) -> Derivability;
79	}
80	
81	/// How a per-rule timeout is treated. See the residual note in BEHAVIOR.md §7:
82	/// a real per-rule timeout was not observable, so the policy is explicit here.
83	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
84	pub enum TimeoutPolicy {
85	    /// Suppress the whole rule's warning when any of its probes times out
86	    /// (fail-open; the chosen default, consistent with `timeout=0` suppressing
87	    /// all output).
88	    SuppressRule,
89	    /// Treat a timed-out probe like `Derivable` (skip only that variable) and
90	    /// still report the variables that were definitively not derivable.
91	    SkipVariable,
92	}
93	
94	impl Default for TimeoutPolicy {
95	    fn default() -> Self {
96	        TimeoutPolicy::SuppressRule
97	    }
98	}
99	
100	// --------------------------------------------------------------------------
101	// Entry points
102	// --------------------------------------------------------------------------
103	
104	/// Run the message-derivation check over a theory with the default timeout
105	/// policy. `timeout_secs` mirrors `--derivcheck-timeout`: `0` deactivates the
106	/// check and returns an empty report without consulting the solver.
107	pub fn message_derivation_checks<S: DerivabilitySolver>(
108	    thy: &Theory,
109	    solver: &S,
110	    timeout_secs: u64,
111	) -> WfReport {
112	    message_derivation_checks_with(thy, solver, timeout_secs, TimeoutPolicy::default())
113	}
114	
115	/// As [`message_derivation_checks`], with an explicit timeout policy.
116	pub fn message_derivation_checks_with<S: DerivabilitySolver>(
117	    thy: &Theory,
118	    solver: &S,
119	    timeout_secs: u64,
120	    timeout_policy: TimeoutPolicy,
121	) -> WfReport {
122	    // `--derivcheck-timeout=0` deactivates the check entirely.
123	    if timeout_secs == 0 {
124	        return Vec::new();
125	    }
126	
127	    // Per-rule findings, kept in theory (source) order.
128	    let mut blocks: Vec<(String, Vec<VarSpec>)> = Vec::new();
129	
130	    for item in &thy.items {
131	        let rule = match item {
132	            TheoryItem::Rule(rule) => rule,
133	            _ => continue, // only protocol rules; intruder rules are out of scope
134	        };
135	        // A rule tagged [no_derivcheck] is skipped.
136	        if rule.attributes.iter().any(|a| matches!(a, RuleAttr::NoDerivCheck)) {
137	            continue;
138	        }
139	
140	        let candidates = candidate_variables(rule);
141	        let mut flagged: Vec<VarSpec> = Vec::new();
142	        let mut rule_timed_out = false;
143	
144	        for var in &candidates {
145	            let probe = DerivProbe {
146	                rule_name: &rule.name,
147	                rule,
148	                variable: var,
149	                premises: &rule.premises,
150	                timeout_secs,
151	            };
152	            match solver.check(&probe) {
153	                Derivability::Derivable => {}
154	                Derivability::NotDerivable => flagged.push(var.clone()),
155	                Derivability::TimedOut => match timeout_policy {
156	                    TimeoutPolicy::SuppressRule => {
157	                        rule_timed_out = true;
158	                        break;
159	                    }
160	                    TimeoutPolicy::SkipVariable => {}
161	                },
162	            }
163	        }
164	
165	        if rule_timed_out {
166	            continue;
167	        }
168	        if !flagged.is_empty() {
169	            sort_variables(&mut flagged);
170	            blocks.push((rule.name.clone(), flagged));
171	        }
172	    }
173	
174	    if blocks.is_empty() {
175	        return Vec::new();
176	    }
177	
178	    // The intro paragraph is emitted once, then one entry per failing rule; all
179	    // share the topic so the report groups them under a single header.
180	    let mut report: WfReport = Vec::with_capacity(blocks.len() + 1);
181	    report.push(WfError::new(DERIVATION_TOPIC, DERIVATION_INTRO));
182	    for (name, vars) in blocks {
183	        report.push(WfError::new(DERIVATION_TOPIC, rule_block(&name, &vars)));
184	    }
185	    report
186	}
187	
188	// --------------------------------------------------------------------------
189	// Probe construction
190	// --------------------------------------------------------------------------
191	
192	/// The candidate variables handed to the solver for one rule: every distinct
193	/// variable occurring in the rule's premises, actions, conclusions, and let
194	/// bindings, in first-occurrence order (order is irrelevant — the flagged subset
195	/// is re-sorted for display). The solver decides which are actually derivable,
196	/// so this set is a safe superset: public names, `Fr`-bound fresh names, and
197	/// state-fact-bound variables are all resolved to `Derivable` by the solver.
198	pub fn candidate_variables(rule: &Rule) -> Vec<VarSpec> {
199	    let mut out: Vec<VarSpec> = Vec::new();
200	    let mut seen: HashSet<VarSpec> = HashSet::new();
201	    let push = |t: &Term, out: &mut Vec<VarSpec>, seen: &mut HashSet<VarSpec>| {
202	        collect_vars(t, &mut |v| {
203	            if seen.insert(v.clone()) {
204	                out.push(v.clone());
205	            }
206	        });
207	    };
208	    for f in &rule.premises {
209	        for a in &f.args {
210	            push(a, &mut out, &mut seen);
211	        }
212	    }
213	    for f in &rule.actions {
214	        for a in &f.args {
215	            push(a, &mut out, &mut seen);
216	        }
217	    }
218	    for f in &rule.conclusions {
219	        for a in &f.args {
220	            push(a, &mut out, &mut seen);
221	        }
222	    }
223	    for lb in &rule.let_block {
224	        push(&lb.var, &mut out, &mut seen);
225	        push(&lb.value, &mut out, &mut seen);
226	    }
227	    out
228	}
229	
230	/// Walk a term, invoking `f` on every variable occurrence.
231	fn collect_vars(term: &Term, f: &mut impl FnMut(&VarSpec)) {
232	    match term {
233	        Term::Var(v) => f(v),
234	        Term::PubLit(_)
235	        | Term::FreshLit(_)
236	        | Term::NatLit(_)
237	        | Term::Number(_)
238	        | Term::NumberOne
239	        | Term::NatOne
240	        | Term::DhNeutral => {}
241	        Term::App(_, args) | Term::Pair(args) => {
242	            for a in args {
243	                collect_vars(a, f);
244	            }
245	        }
246	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
247	            collect_vars(a, f);
248	            collect_vars(b, f);
249	        }
250	        Term::PatMatch(a) => collect_vars(a, f),
251	    }
252	}
253	
254	// --------------------------------------------------------------------------
255	// Variable ordering and rendering
256	// --------------------------------------------------------------------------
257	
258	/// Sort flagged variables into report order and drop duplicates. The order is
259	/// ascending by `(sort-rank, name lexicographically, index numerically)`.
260	pub fn sort_variables(vars: &mut Vec<VarSpec>) {
261	    vars.sort_by(var_order_key);
262	    vars.dedup();
263	}
264	
265	/// Total order used to sort reported variables (see BEHAVIOR.md §6).
266	fn var_order_key(a: &VarSpec, b: &VarSpec) -> std::cmp::Ordering {
267	    sort_rank(a.sort)
268	        .cmp(&sort_rank(b.sort))
269	        .then_with(|| a.name.cmp(&b.name)) // lexicographic string comparison
270	        .then_with(|| a.idx.cmp(&b.idx)) // numeric index comparison
271	}
272	
273	/// Sort-tag rank. Observed among reportable (non-derivable) variables:
274	/// `Fresh < Msg`. Message-sort variables carry either `Msg` or `Untagged` and
275	/// rank together. Other sorts (`Pub`, `Node`, `Nat`, `Suffix`) do not occur as
276	/// reported variables — public names are always derivable and node/nat are not
277	/// message terms — so their relative rank is unobserved and placed last.
278	fn sort_rank(sort: SortHint) -> u8 {
279	    match sort {
280	        SortHint::Fresh => 0,
281	        SortHint::Msg | SortHint::Untagged => 1,
282	        _ => 2,
283	    }
284	}
285	
286	/// Render one variable as the reference tool spells it in the warning: fresh
287	/// names carry a `~` prefix, public names a `$` prefix, message names none; a
288	/// nonzero index is appended as `.idx` (e.g. `x.2`).
289	pub fn render_variable(v: &VarSpec) -> String {
290	    let prefix = match v.sort {
291	        SortHint::Fresh => "~",
292	        SortHint::Pub => "$",
293	        _ => "",
294	    };
295	    if v.idx == 0 {
296	        format!("{}{}", prefix, v.name)
297	    } else {
298	        format!("{}{}.{}", prefix, v.name, v.idx)
299	    }
300	}
301	
302	/// The per-rule block body: `"Rule <name>: \nFailed to derive Variable(s): <v1>, <v2>, ..."`.
303	/// Note the trailing space after the colon on the first line.
304	fn rule_block(rule_name: &str, vars: &[VarSpec]) -> String {
305	    let list = vars
306	        .iter()
307	        .map(render_variable)
308	        .collect::<Vec<_>>()
309	        .join(", ");
310	    format!("Rule {}: \nFailed to derive Variable(s): {}", rule_name, list)
311	}
312	
313	// --------------------------------------------------------------------------
314	// Rendering
315	// --------------------------------------------------------------------------
316	
317	/// A topic header exactly as the reference tool renders it: the title, then a
318	/// newline, then a run of `=` as long as the title, then a newline.
319	pub fn underline_topic(title: &str) -> String {
320	    let bar: String = "=".repeat(title.chars().count());
321	    format!("{}\n{}\n", title, bar)
322	}
323	
324	/// The distinct topics present in a report.
325	pub fn topics(report: &WfReport) -> BTreeSet<String> {
326	    report.iter().map(|e| e.topic.clone()).collect()
327	}
328	
329	/// Render the `Message Derivation Checks` topic block byte-exactly. Returns the
330	/// empty string for an empty report. The block has no trailing newline; the
331	/// surrounding report writer adds separators between topic blocks.
332	pub fn render_derivation_report(report: &WfReport) -> String {
333	    let messages: Vec<&str> = report
334	        .iter()
335	        .filter(|e| e.topic == DERIVATION_TOPIC)
336	        .map(|e| e.message.as_str())
337	        .collect();
338	    if messages.is_empty() {
339	        return String::new();
340	    }
341	    format!(
342	        "{}\n{}",
343	        underline_topic(DERIVATION_TOPIC),
344	        messages.join("\n\n")
345	    )
346	}
