401	    // A stub solver that flags exactly the variables whose rendered name is in
402	    // its set as NotDerivable; everything else Derivable.
403	    struct FlagByName {
404	        not_derivable: HashSet<String>,
405	    }
406	    impl FlagByName {
407	        fn new(names: &[&str]) -> Self {
408	            FlagByName { not_derivable: names.iter().map(|s| s.to_string()).collect() }
409	        }
410	    }
411	    impl DerivabilitySolver for FlagByName {
412	        fn check(&self, probe: &DerivProbe) -> Derivability {
413	            if self.not_derivable.contains(&probe.variable.name) {
414	                Derivability::NotDerivable
415	            } else {
416	                Derivability::Derivable
417	            }
418	        }
419	    }
