421	    // A stub that always times out.
422	    struct AlwaysTimeout;
423	    impl DerivabilitySolver for AlwaysTimeout {
424	        fn check(&self, _: &DerivProbe) -> Derivability {
425	            Derivability::TimedOut
426	        }
427	    }
