437	    // ---- byte-exact output (matches captured oracle text) ----
438	
439	    #[test]
440	    fn single_rule_block_is_byte_exact() {
441	        // Rule R: [ In(h(w)) ] --> [ Out('ok') ]; solver flags w.
442	        let r = rule(
443	            "R",
444	            vec![fact("In", vec![app("h", vec![v("w")])])],
445	            vec![fact("Out", vec![Term::PubLit("ok".into())])],
446	            vec![],
447	        );
448	        let thy = theory(vec![TheoryItem::Rule(r)]);
449	        let report = message_derivation_checks(&thy, &FlagByName::new(&["w"]), 5);
450	
451	        // `concat!` keeps the trailing space after "Rule R:" explicit.
452	        let expected = concat!(
453	            "Message Derivation Checks\n",
454	            "=========================\n",
455	            "\n",
456	            "  The variables of the following rule(s) are not derivable from their premises, you may be performing unintended pattern matching.\n",
