507	    fn variables_sorted_by_sort_then_name_then_index() {
508	        // Feed a deliberately scrambled candidate order; all flagged.
509	        let vars = vec![
510	            v("v2"),
511	            Term::Var(fresh_var("zzz")),
512	            Term::Var(msg_var_idx("x", 10)),
