580	    #[test]
581	    fn derivable_rule_is_omitted_and_theory_order_preserved() {
582	        // Good (all derivable) then Bad (w flagged); only Bad appears.
583	        let good = rule("Good", vec![fact("In", vec![v("x")])], vec![fact("Out", vec![v("x")])], vec![]);
584	        let bad = rule("Bad", vec![fact("In", vec![app("h", vec![v("w")])])], vec![], vec![]);
585	        let thy = theory(vec![TheoryItem::Rule(good), TheoryItem::Rule(bad)]);
